mapper.select:
SELECT clazz.id, clazz.name, clazz.room, clazz.begin_date AS beginDate, clazz.end_date AS endDate, clazz.master_id AS masterId, dept.name AS subject, clazz.create_time AS createTime, clazz.update_time AS updateTime, emp.name AS masterName FROM clazz LEFT JOIN emp ON clazz.master_id = emp.id LEFT JOIN dept ON clazz.subject = dept.id
and clazz.name like concat('%',#{name},'%')
and clazz.begin_date >= #{begin}
and clazz.end_date <= #{end}
ORDER BY clazz.update_time DESC
